import{c as a,Q as o,j as t,m as d}from"./chunks/framework.D9IbVcwA.js";const u=JSON.parse('{"title":"017-mm-heap-1 · 堆管理","description":"","frontmatter":{"title":"017-mm-heap-1 · 堆管理"},"headers":[],"relativePath":"hands-on/017-mm-heap-1.md","filePath":"hands-on/017-mm-heap-1.md","lastUpdated":1779686691000}'),s={name:"hands-on/017-mm-heap-1.md"};function c(i,e,p,r,n,l){return o(),t("div",null,[...e[0]||(e[0]=[d(`<h1 id="_017-1-blockheader-数据结构与堆初始化" tabindex="-1">017-1 BlockHeader 数据结构与堆初始化 <a class="header-anchor" href="#_017-1-blockheader-数据结构与堆初始化" aria-label="Permalink to &quot;017-1 BlockHeader 数据结构与堆初始化&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>到 tag 016 为止，PMM 能分配物理页，VMM 能把虚拟地址映射到物理页——我们的内存管理&quot;基础设施建设&quot;已经完工了。但如果你现在想在内核里分配一个 100 字节的小结构体，唯一的办法就是从 PMM 拿一整页 4096 字节，然后只用了 100 字节，剩下的 3996 字节全部浪费。内核里到处都是这种零碎的小分配——字符串缓冲区、链表节点、设备描述符——每一样都消耗一整页的话，内存利用率会惨不忍睹。</p><p>这一章我们开始搭建堆分配器（Heap Allocator），它坐在 PMM 和 VMM 之上，把整页的虚拟内存切成任意大小的小块，按需分配给内核使用。这是内存管理层级中的第三层：PMM 管物理页、VMM 管虚拟映射、Heap 管子页粒度的分配。本章聚焦于最基础的部分——每个内存块的元数据头部（BlockHeader）和堆区域的初始化流程。</p><p>知识前置：你需要熟悉 tag 016 中 VMM 的 <code>map</code> 接口（将虚拟地址映射到物理页）以及 PMM 的 <code>alloc_page</code> 接口（分配一个物理页）。堆初始化的核心工作就是&quot;从 VMM 那里借一段虚拟地址空间，映射好物理页，然后把整段空间标记为一个大空闲块&quot;。</p><p>本章所有代码都在 <code>kernel/mm/</code> 目录下。新文件只有两个：<code>heap.hpp</code>（头文件，约 126 行）和 <code>heap.cpp</code>（实现，约 353 行）。编译时需要在 <code>kernel/CMakeLists.txt</code> 的 <code>big_kernel_common</code> 库中添加 <code>mm/heap.cpp</code>。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="为什么需要堆分配器" tabindex="-1">为什么需要堆分配器？ <a class="header-anchor" href="#为什么需要堆分配器" aria-label="Permalink to &quot;为什么需要堆分配器？&quot;">​</a></h3><p>你可以把 PMM 想象成一个只批发不零售的建材供应商——你要买砖头，最少也得买一整托盘（4096 块），不接受拆零。VMM 则是运输公司，帮你把托盘送到指定的仓库位置。但实际装修的时候，你需要的是&quot;给我 3 块砖&quot;&quot;给我半袋水泥&quot;这种小份量的分配。堆分配器就是零售商——它从批发商那里整托盘地进货，然后按客户需求拆开零售。</p><p>OSDev Wiki 上有一篇很好的 Memory Allocation 概述（<a href="https://wiki.osdev.org/Memory_Allocation%EF%BC%89%EF%BC%8C%E9%87%8C%E9%9D%A2%E6%8F%8F%E8%BF%B0%E4%BA%86%E7%BB%8F%E5%85%B8%E7%9A%84%E5%86%85%E5%AD%98%E7%AE%A1%E7%90%86%E5%B1%82%E7%BA%A7%E6%9E%B6%E6%9E%84%EF%BC%8C%E5%92%8C" target="_blank" rel="noreferrer">https://wiki.osdev.org/Memory_Allocation），里面描述了经典的内存管理层级架构，和</a> Cinux 的设计如出一辙：PMM 在最底层分配整页物理内存，VMM 负责虚拟地址映射，堆分配器在最上层提供任意大小的分配接口。每一层只和直接相邻的层打交道——堆分配器不直接碰物理内存，它只向 VMM 请求更多的虚拟地址空间。</p><p>这个三层架构在工业界被广泛采用。Linux 内核的三层是 buddy（物理页管理）-&gt; slab（固定大小对象缓存）-&gt; kmalloc（通用分配接口）。FreeRTOS 虽然没有 VMM（它是单地址空间的 RTOS），但它的 heap_4 本质上也是坐在 PMM 之上的 sub-page 分配器。理解了这个分层模型，你就能看懂几乎所有 OS 的内存管理设计。</p><h3 id="blockheader-每个块的-身份证" tabindex="-1">BlockHeader：每个块的&quot;身份证&quot; <a class="header-anchor" href="#blockheader-每个块的-身份证" aria-label="Permalink to &quot;BlockHeader：每个块的&quot;身份证&quot;&quot;">​</a></h3><p>堆分配器管理的内存被划分成一个个连续的块（block），每个块前面紧贴着一段固定大小的元数据——BlockHeader。这个头部包含以下信息：一个 32 位的 magic 常量（固定值 0xDEADBEEF），用于运行时检测内存损坏和 double-free；一个 32 位的 size 字段，记录紧跟在头部后面的 payload 有多少字节；一个 32 位的 free 标志，值为 1 表示空闲、0 表示已分配；一个 12 字节的填充字段，把头部撑到合适的尺寸；以及一个 next 指针，把空闲块串成一个链表。</p><p>整个 BlockHeader 的尺寸被硬性规定为 32 字节，通过 <code>static_assert</code> 在编译期强制检查。这个数字不是随便选的——32 字节正好满足 16 字节对齐要求的整数倍，而且足够容纳上述所有字段。填充字段的存在就是为了把头部对齐到这个尺寸，以后如果你需要往头部里加新字段，可以缩减填充而不需要改常量。结构体加上 <code>[[gnu::packed]]</code> 属性，告诉编译器不要插入额外的对齐填充——我们需要精确控制每个字节的位置。</p><p>你可能觉得 magic 常量有点&quot;多余&quot;——它不是硬件要求，纯粹是软件层面的防御性编程。但在内核开发中，内存损坏的 bug 往往是最难排查的。如果一个指针错误导致某块内存被意外覆写，magic 常量会在 free 的时候立刻暴露问题，而不是让错误悄悄传播到系统崩溃才被发现。FreeRTOS 的 heap_4 实现就没有 magic 校验，在生产环境中可能无所谓，但在教学 OS 里这种安全网特别有价值。</p><p>关于 <code>[[gnu::packed]]</code> 在 x86-64 上的安全性：packed 属性意味着 BlockHeader 的 <code>next</code> 指针（偏移量 24）可能不是自然对齐的（8 字节指针从 24 + 12 = 24 的位置开始是 8 的倍数——实际上在这里恰好是）。但在其他场景下，如果 padding 更小，<code>next</code> 可能从奇数地址开始。x86-64 硬件支持未对齐访问（不像 ARM 那样会触发 alignment fault），所以不会 crash，但未对齐访问可能稍慢。在 Cinux 的场景下，这种性能差异可以忽略不计。</p><h3 id="空闲链表-堆分配器的核心数据结构" tabindex="-1">空闲链表：堆分配器的核心数据结构 <a class="header-anchor" href="#空闲链表-堆分配器的核心数据结构" aria-label="Permalink to &quot;空闲链表：堆分配器的核心数据结构&quot;">​</a></h3><p>堆分配器用一个单链表来追踪所有空闲块——free_list_ 指向链表头，每个空闲块的 BlockHeader 中的 next 指针指向下一个空闲块。已分配的块不在链表中——它们的 next 指针为空，分配器不需要追踪已分配的块，因为 <code>free</code> 操作可以通过指针减去 HEADER_SIZE 直接定位到 BlockHeader。</p><p>这种设计有一个显而易见的限制：遍历空闲链表是 O(n) 的操作，n 是空闲块的数量。如果堆里碎片化严重（大量小空闲块），分配操作会变慢。但在内核的典型工作负载下，空闲块数量通常不会太多——几十个到几百个的水平——线性扫描完全够用。Linux 内核的 SLOB 分配器用的也是类似的 first-fit 线性扫描策略，在嵌入式场景中表现良好。</p><p>为什么不用双向链表？单链表在删除节点时需要从头遍历找前驱，这是一个 O(n) 的操作——我们在 coalesce 中会大量遇到这个场景。但如果用双向链表，每个 BlockHeader 需要额外存一个 prev 指针，把头部从 32 字节膨胀到 40 字节，这会让每个块的元数据开销增加 25%。对于教学内核来说，32 字节这个&quot;2 的幂&quot;的尺寸带来的地址计算简便性更重要。</p><h3 id="堆的虚拟地址选址" tabindex="-1">堆的虚拟地址选址 <a class="header-anchor" href="#堆的虚拟地址选址" aria-label="Permalink to &quot;堆的虚拟地址选址&quot;">​</a></h3><p>Cinux 把堆放在虚拟地址 0xFFFF800000000000——这是一个 higher-half canonical address，位于内核空间的&quot;下半区&quot;。这个地址的选择有几个考量：它远离内核代码段（0xFFFFFFFF80000000 附近），不会和内核映像、页表、MMIO 映射冲突；它足够低，将来可以向上扩展很大的范围；而且它是一个 4KB 对齐的地址，满足分页映射的要求。初始大小是 64 KB（16 个物理页），足够内核启动阶段的分配需求。</p><p>如果你好奇这个地址在页表中的位置：PML4 索引是 256（<code>(0xFFFF800000000000 &gt;&gt; 39) &amp; 0x1FF</code>），恰好是 canonical 高半区的第一个 PML4 表项。从 PML4[256] 开始一直到 PML4[511]（内核代码段所在位置），中间有 256 个 PML4 表项可用，对应 256 * 512 GB = 128 TB 的虚拟地址空间。堆从 PML4[256] 的起始处开始，可以向上连续增长非常大的范围，不必担心和更高地址的内核数据结构冲突。</p><p>参考：</p><ul><li><a href="https://wiki.osdev.org/Memory_Allocation" target="_blank" rel="noreferrer">OSDev Wiki - Memory Allocation</a></li><li><a href="https://github.com/dreamportdev/Osdev-Notes/blob/master/04_Memory_Management/05_Heap_Allocation.md" target="_blank" rel="noreferrer">dreamportdev Osdev Notes - Heap Allocation</a></li></ul><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-定义-blockheader-结构体" tabindex="-1">Step 1: 定义 BlockHeader 结构体 <a class="header-anchor" href="#step-1-定义-blockheader-结构体" aria-label="Permalink to &quot;Step 1: 定义 BlockHeader 结构体&quot;">​</a></h3><p><strong>目标</strong>: 创建一个精确 32 字节的块头部结构体，包含 magic、size、free、填充和 next 指针。</p><p><strong>设计思路</strong>: 结构体需要用 <code>[[gnu::packed]]</code> 属性确保编译器不会插入额外的对齐填充。字段依次是：magic（uint32_t，固定 0xDEADBEEF）、size（uint32_t，payload 大小）、free（uint32_t，空闲标志）、_pad（uint8_t[12]，填充到 32 字节）、next（BlockHeader*，链表指针）。加上 packed 属性后，这几个字段的总大小需要恰好是 32 字节——magic 4 + size 4 + free 4 + _pad 12 + next 8 = 32。用 <code>static_assert(sizeof(BlockHeader) == 32)</code> 做编译期检查。</p><p><strong>实现约束</strong>: 结构体定义在 <code>kernel/mm/heap.hpp</code> 中，命名空间 <code>cinux::mm</code>。magic 常量不在结构体里定义，而是作为 <code>heap.cpp</code> 中的 <code>constexpr uint32_t</code> 常量（因为它是实现细节，外部不需要知道具体的 magic 值）。</p><p><strong>踩坑预警</strong>: 如果你将来需要给 BlockHeader 添加新字段，必须同步修改 _pad 的大小，确保总大小仍然是 32 字节。如果你忘了改 static_assert，编译器会立刻报错提醒你——但如果你的修改恰好保持了 32 字节（比如把 _pad 缩了 4 字节又加了一个 uint32_t 字段），assert 不会触发，你需要自己确认新布局的合理性。另外，<code>[[gnu::packed]]</code> 意味着 next 指针可能不是自然对齐的——在某些架构上访问未对齐的指针会导致性能下降甚至 crash，但 x86-64 对未对齐访问有硬件支持，所以不用担心。</p><p><strong>验证</strong>: 结构体定义完成后，编译即可验证 static_assert 通过（如果大小不是 32 字节，编译错误信息会告诉你实际的 sizeof 值，检查你的字段声明是否遗漏了什么）。</p><p>你可以用以下方式在编译时确认 BlockHeader 的布局：</p><p>你可以用以下方式在编译时看到 BlockHeader 的布局详情：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">x86_64-elf-g++</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -std=c++20</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -dM</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/null</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 检查编译器版本</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果编译器支持 <code>__builtin_dump_struct</code>（Clang），可以直接在运行时打印结构体的字段偏移和大小。GCC 目前没有这个特性，但你可以手写一个 <code>dump_block_header</code> 函数，用 <code>offsetof</code> 打印每个字段的偏移量，确认布局是否符合预期。</p><h3 id="step-2-声明-heap-类和全局实例" tabindex="-1">Step 2: 声明 Heap 类和全局实例 <a class="header-anchor" href="#step-2-声明-heap-类和全局实例" aria-label="Permalink to &quot;Step 2: 声明 Heap 类和全局实例&quot;">​</a></h3><p><strong>目标</strong>: 定义堆分配器的公开接口和私有状态。</p><p><strong>设计思路</strong>: Heap 类的公开接口包括四个方法：<code>init(virt_base, initial_size)</code> 初始化堆区域；<code>alloc(size, align)</code> 分配一块指定大小和对齐的内存，返回 payload 指针；<code>free(ptr)</code> 释放之前分配的内存；<code>dump_stats()</code> 打印堆的统计信息到内核日志。私有部分包括：<code>expand(min_bytes)</code> 在堆空间不足时扩展；<code>coalesce(block)</code> 合并相邻空闲块；以及成员变量 base_（堆的虚拟基地址）、size_（总大小）、used_（已使用大小）、free_list_（空闲链表头指针）。</p><p>全局实例 <code>g_heap</code> 声明为 <code>extern Heap g_heap</code>，在 <code>heap.cpp</code> 中定义。整个内核通过 <code>cinux::mm::g_heap</code> 访问唯一的堆实例。这种&quot;单例&quot;设计在内核中很常见——Linux 有全局的 <code>kmalloc</code> 接口，FreeRTOS 用一个静态数组 <code>ucHeap[configTOTAL_HEAP_SIZE]</code>。Cinux 的做法更灵活——堆区域不是静态数组，而是通过 VMM 动态映射的虚拟地址空间，可以在运行时扩展。</p><p><strong>实现约束</strong>: 类定义在 <code>kernel/mm/heap.hpp</code>，命名空间 <code>cinux::mm</code>。成员变量使用类内初始化（<code>base_{}</code>、<code>size_{}</code> 等），默认构造的对象所有状态为零/空指针。alloc 的 align 参数有默认值 16。</p><p><strong>踩坑预警</strong>: alloc 的返回类型是 <code>void*</code>——当请求大小为 0 时必须返回 <code>nullptr</code>，而不是一个有效的指针。这是 C 标准库 malloc 的语义，也是 C++ operator new 的要求。如果你返回了一个指向零字节 payload 的指针，调用者可能会试图往里面写数据，虽然没分配任何空间，但可能意外覆写相邻块的头部。</p><p><strong>验证</strong>: 头文件编写完成后，在 <code>kernel/main.cpp</code> 中 include <code>kernel/mm/heap.hpp</code>，尝试引用 <code>cinux::mm::g_heap</code>——编译通过即可确认接口定义正确。</p><p>另一个值得验证的细节是成员变量的初始值。在堆初始化之前（<code>init</code> 调用之前），如果你意外调用了 <code>dump_stats</code> 或其他方法，所有成员都应该是零——<code>base_</code> 是 0、<code>size_</code> 是 0、<code>used_</code> 是 0、<code>free_list_</code> 是 <code>nullptr</code>。这意味着在未初始化状态下调用 <code>alloc</code> 会立即搜索 <code>nullptr</code>，循环直接退出，然后触发 <code>expand</code>——而 expand 会访问 <code>base_ + size_</code>（即地址 0），导致 page fault。这个&quot;fail-fast&quot;的行为虽然不够优雅，但至少不会静默地踩内存。</p><h3 id="step-3-实现-heap-init-初始化函数" tabindex="-1">Step 3: 实现 Heap::init 初始化函数 <a class="header-anchor" href="#step-3-实现-heap-init-初始化函数" aria-label="Permalink to &quot;Step 3: 实现 Heap::init 初始化函数&quot;">​</a></h3><p><strong>目标</strong>: 将指定虚拟地址范围的物理页映射好，创建初始空闲块。</p><p><strong>设计思路</strong>: init 做五件事。第一，把 initial_size 向上对齐到页面大小（4096 字节）——如果调用者传入 60000，对齐后就是 65536（16 页）。第二，逐页分配物理内存并映射：循环从 PMM 调用 alloc_page 获取物理页，然后用 VMM::map 把它映射到堆区域的对应虚拟地址。映射标志位是 present + writable（0x03）。第三，把整个映射好的区域清零——这既是安全考虑（防止泄漏旧数据），也为了后续创建 BlockHeader 时不需要逐字段清零未使用的部分。第四，在堆区域的起始位置创建初始空闲块——这个块覆盖整个堆区域，它的 size 等于总大小减去 HEADER_SIZE（因为头部本身占 32 字节），free 标志为 1，next 为 nullptr。第五，保存堆的元数据（基地址、总大小、已使用量为零、空闲链表指向初始块）。</p><p>这五个步骤的顺序不能随意调换。映射必须在清零之前（否则清零操作会触发 page fault，因为虚拟地址还没有映射到物理页）。清零必须在创建 BlockHeader 之前（否则清零会把刚写好的 header 也擦掉）。BlockHeader 的创建必须在保存元数据之前（因为 free_list_ 需要指向已经创建好的 block）。如果你调换了映射和清零的顺序，运行时表现取决于 CPU 是否有 TLB 缓存——有时候&quot;恰好能工作&quot;（因为之前的映射残留），有时候 crash，这种不可靠的 bug 最难定位。</p><p>还有一个值得注意的细节：初始空闲块的 <code>first-&gt;size</code> 应该等于 <code>aligned_size - HEADER_SIZE</code>，而不是 <code>aligned_size</code>。前者意味着第一个 payload 从 header 结束处开始，大小等于总区域减去 32 字节的头部开销。如果错误地设为 <code>aligned_size</code>，第一个块的 payload 会延伸到堆区域之外 32 字节，下一次分配可能踩到未映射的内存。这个 off-by-one 错误在初始状态下不容易发现（因为 64 KB 的堆远大于初始分配），但在堆空间紧张时会触发 page fault。</p><p><strong>实现约束</strong>: 函数定义在 <code>kernel/mm/heap.cpp</code> 中。需要 include <code>kernel/mm/pmm.hpp</code>、<code>kernel/mm/vmm.hpp</code>、<code>kernel/arch/x86_64/paging_config.hpp</code>（获取 PAGE_SIZE）。常量 HEADER_SIZE 定义为 <code>sizeof(BlockHeader)</code>，PAGE_FLAGS 定义为 0x03。</p><p><strong>踩坑预警</strong>: init 过程中如果 PMM 返回 0（内存不足），必须立即停止并报告错误——不能继续映射一个空物理页，否则后续对堆内存的读写会触发 page fault。另外，memzero 清零操作必须在映射完成之后、创建 BlockHeader 之前——如果顺序搞反了，清零会把刚写好的 BlockHeader 也清掉。</p><p>一个容易忽略的边界情况：如果调用者传入的 <code>initial_size</code> 为 0 会发生什么？<code>align_up(0, PAGE_SIZE)</code> 返回 0，映射循环不会执行（<code>0 &lt; 0</code> 为 false），memzero 也不会清零任何东西，然后创建 BlockHeader 时 <code>first-&gt;size = 0 - HEADER_SIZE</code> 会下溢为一个巨大的无符号数。这是一个需要防范的 bug——可以在 init 开头加入参数校验。当前的实现假设调用者（main.cpp）总是传入合理的值（64 KB），所以没有做这个检查，但防御性编程永远是值得的。</p><p><strong>验证</strong>: 在 <code>kernel/main.cpp</code> 的启动序列中，在 VMM 初始化之后、framebuffer 初始化之前，调用 <code>g_heap.init(0xFFFF800000000000ULL, 64 * 1024)</code>。串口输出应该显示 <code>[HEAP] Initialised at 0x...000, size 64 KB</code>。</p><p>你可以通过以下检查进一步确认初始化的正确性。第一，在 init 之后立刻读取 <code>g_heap</code> 的 <code>base_</code> 值，应该是 <code>0xFFFF800000000000</code>。第二，<code>size_</code> 应该等于传入的 <code>initial_size</code>（64 KB），因为 64 KB 已经是页对齐的（64 KB / 4096 = 16 页）。第三，如果你传入一个非页对齐的大小（比如 60000），<code>size_</code> 应该被向上对齐到 65536（64 KB）。你可以用 <code>kprintf</code> 打印这些值做快速检查。</p><h3 id="step-4-实现-dump-stats-调试输出" tabindex="-1">Step 4: 实现 dump_stats 调试输出 <a class="header-anchor" href="#step-4-实现-dump-stats-调试输出" aria-label="Permalink to &quot;Step 4: 实现 dump_stats 调试输出&quot;">​</a></h3><p><strong>目标</strong>: 遍历空闲链表，统计空闲空间总量和块数量，打印汇总信息。</p><p><strong>设计思路</strong>: dump_stats 从 free_list_ 开始遍历链表，对每个块累加它的 size（只统计 free=1 的块），同时计数总块数。最终通过 kprintf 输出四个数字：总堆大小（KB）、已使用量（KB）、空闲链表中的空闲空间（KB）、空闲块数量。这个函数在调试时非常有用——你可以随时调用它来检查堆的健康状况。</p><p>注意 dump_stats 输出的 <code>free_list</code> 值和 <code>total - used</code> 不一定相等。差值来自两个来源：一是内部碎片（front padding 和 MIN_SPLIT 以下的 tail remainder），这些空间被分配但不在 payload 中；二是空闲链表中的块本身的 header 占用的空间（header 的 32 字节从&quot;可用 payload&quot;的角度看是&quot;浪费&quot;的，但从 <code>size_</code> 的角度看是&quot;堆的一部分&quot;）。理解这个差值对调试碎片化问题很重要——如果你发现 <code>total - used</code> 远大于 <code>free_list</code>，说明碎片化严重。</p><p><strong>实现约束</strong>: 函数是 const 方法——它只读不写。输出格式要统一，方便 grep 或者肉眼比对。dump_stats 还可以用来发现链表损坏——如果遍历过程中遇到了 magic 不正确的块，程序可能会 crash。一个更健壮的版本可以在遍历时加入 magic 校验。</p><p><strong>踩坑预警</strong>: dump_stats 遍历的是空闲链表，不是堆中的所有块。已分配的块不在链表中，所以&quot;已使用量&quot;不是从链表中统计出来的，而是从 used_ 成员变量读取的。如果你发现 free_total + used 和 total 对不上，可能是 coalesce 或 expand 的逻辑有问题，导致某些空间既没有被计入 used_ 也没有出现在空闲链表中。</p><p><strong>验证</strong>: 在 init 之后立即调用 <code>g_heap.dump_stats()</code>。预期输出是：total=64 KB，used=0 KB，free_list≈63 KB（减去一个 HEADER_SIZE 的开销），blocks=1。</p><p>关于 memzero 的性能有一个值得注意的点：当前的实现是逐字节清零的，对于 64 KB 的堆区域来说需要循环 65536 次。这在内核启动阶段（只调用一次 init）是可以接受的，但如果你想优化，可以用 8 字节的 uint64_t 赋值代替逐字节操作，理论上速度提升 8 倍。不过实际瓶颈可能在内存访问延迟而非循环次数——现代 CPU 的 store buffer 可以吸收大量的顺序写入。在 Cinux 的当前阶段，逐字节清零的简单实现优先于微优化。</p><h3 id="step-5-将堆初始化插入内核启动序列" tabindex="-1">Step 5: 将堆初始化插入内核启动序列 <a class="header-anchor" href="#step-5-将堆初始化插入内核启动序列" aria-label="Permalink to &quot;Step 5: 将堆初始化插入内核启动序列&quot;">​</a></h3><p><strong>目标</strong>: 在 main.cpp 的启动流程中，在正确位置调用堆初始化。</p><p><strong>设计思路</strong>: 堆必须初始化在 VMM 之后——因为 init 需要调用 VMM::map 来映射物理页。同时应该尽量早——因为后续的 C++ 全局对象构造、framebuffer 初始化、设备驱动初始化都可能用到动态内存分配。所以 Cinux 把堆初始化放在启动序列的第 9 步，紧跟 VMM（第 8 步）之后，在 framebuffer（第 10 步）之前。</p><p>需要定义两个常量：<code>HEAP_VIRT_BASE = 0xFFFF800000000000ULL</code> 和 <code>HEAP_INITIAL_SIZE = 64 * 1024</code>。这两个值目前硬编码在 main.cpp 中，将来如果需要更灵活的配置可以提取到配置头文件。</p><p><code>HEAP_VIRT_BASE</code> 的地址选择需要考虑和链接脚本（linker script）中定义的其他虚拟地址段的冲突。Cinux 的链接脚本定义了 <code>KERNEL_VMA = 0xFFFFFFFF80000000</code> 作为内核代码段的起始地址。堆地址 <code>0xFFFF800000000000</code> 和内核代码段之间有约 128 TB 的距离（从 <code>0xFFFF800000000000</code> 到 <code>0xFFFFFFFF80000000</code>），这个空间足够堆增长到非常大的规模。如果你修改了链接脚本（比如把内核代码段移到了更低的地址），需要确认新的地址不会和堆区域重叠。</p><p><strong>踩坑预警</strong>: 堆的虚拟基地址不能和内核映像、页表、MMIO 区域重叠。0xFFFF800000000000 在 Cinux 的地址空间布局中是安全的，但如果你修改了链接脚本或者增加了新的 MMIO 映射，需要确认没有冲突。另一个要注意的是：如果在堆初始化之前的代码中不小心调用了 operator new（比如某个全局对象的构造函数），它会触发旧的 halt-on-use stub——内核直接死锁。确保堆初始化在所有需要动态内存的操作之前完成。</p><p><strong>验证</strong>: 编译并运行内核：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./build/run_qemu.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>串口输出中应该看到 <code>[HEAP] Initialised at 0xFFFF800000000000, size 64 KB</code>，后面跟着后续初始化步骤的正常输出。如果堆初始化失败（PMM 内存不足），会看到 <code>[HEAP] OOM during init</code> 的错误消息。</p><p>你还可以在 QEMU 的 monitor 中使用 <code>info mem</code> 命令检查堆区域的页表映射是否正确。如果 <code>0xFFFF800000000000</code> 到 <code>0xFFFF80000000FFFF</code> 的地址范围在页表中没有对应的映射项，说明 init 的映射循环有问题——可能是 VMM::map 没有正确创建 PTE，也可能是 PML4 的索引计算错误。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>本章完成了堆分配器的骨架搭建。涉及两个新文件：<code>kernel/mm/heap.hpp</code>（头文件，BlockHeader + Heap 类声明）和 <code>kernel/mm/heap.cpp</code>（init 和 dump_stats 的实现）。需要在 <code>kernel/CMakeLists.txt</code> 的 <code>big_kernel_common</code> 库中添加 <code>mm/heap.cpp</code>。</p><p>构建后运行 QEMU，串口输出应包含：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[BIG] VMM initialised, kernel PML4 at phys ...</span></span>
<span class="line"><span>[HEAP] Initialised at 0xFFFF800000000000, size 64 KB</span></span>
<span class="line"><span>[HEAP] Stats: total=64 KB, used=0 KB, free_list=63 KB, blocks=1</span></span>
<span class="line"><span>[BIG] Framebuffer initialised: ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>如果你在输出中看到 <code>[HEAP] OOM during init at offset XXXX</code> 而不是正常的初始化消息，说明 PMM 无法为堆提供足够的物理页。64 KB 需要 16 个物理页（16 * 4096 = 65536），在 QEMU 默认的 128 MB 内存配置下这不应该发生。检查 PMM 的初始化是否正确解析了 BootInfo 中的内存映射，确保可用物理页的数量足够覆盖内核映像、页表和堆的初始需求。</p><p>本章搭建了骨架，但堆分配器还不能分配内存——下一章将实现 alloc 的 first-fit 搜索和块分裂逻辑。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>init 时 OOM</strong>: 如果看到 <code>[HEAP] OOM during init</code>，说明 PMM 没有足够的物理页来映射 64 KB 的堆区域。检查 PMM 的 free_page_count 输出——64 KB 需要 16 个物理页。在 QEMU 默认配置（128MB 内存）下这不应该发生，但如果你的 PMM 初始化有 bug 导致可用页数不足，就会在这里暴露。</p><p><strong>BlockHeader 大小不对</strong>: 如果 static_assert 触发，检查你的字段类型和数量是否和上面描述的一致。常见的错误是 _pad 的大小写错了（比如写成 <code>_pad[10]</code>），或者忘记加 <code>[[gnu::packed]]</code> 属性导致编译器在 next 指针前插入了 6 字节的对齐填充。</p><p><strong>编译报错 &quot;invalid application of sizeof to incomplete type&quot;</strong>: 这个错误说明编译器在看到 <code>static_assert</code> 时还不知道 BlockHeader 的完整定义。确保 <code>static_assert</code> 放在结构体定义之后（而不是之前）。</p><p><strong>dump_stats 的 free_total 和 total 对不上</strong>: 初始状态下，free_total 应该等于 total - 32（一个 HEADER_SIZE 的开销）。如果差得更多，可能是初始空闲块的 size 计算有误——正确值是 <code>aligned_size - HEADER_SIZE</code>，不是 <code>aligned_size</code>。</p><p><strong>init 后分配立即 page fault</strong>: 这通常意味着映射没有成功建立。在 init 的映射循环中加入 kprintf 打印每次映射的虚拟地址和物理地址，确认 <code>g_pmm.alloc_page()</code> 返回的不是 0，<code>g_vmm.map()</code> 也没有报错。如果 VMM 的 <code>map</code> 函数在映射 higher-half 地址时行为异常（比如它只映射了低于 4 GB 的地址），你需要检查 VMM 实现中的 PML4 索引计算是否正确处理了高地址。</p><h2 id="扩展思考" tabindex="-1">扩展思考 <a class="header-anchor" href="#扩展思考" aria-label="Permalink to &quot;扩展思考&quot;">​</a></h2><p><strong>为什么不用位图代替链表？</strong> 你可能会想到 PMM 用位图管理空闲页，为什么堆分配器不用同样的方式？原因是堆块的大小不固定——位图适用于固定大小的分配单元（比如一个页），每个 bit 代表一个单元的空闲/占用状态。堆块的大小从 1 字节到几 KB 都有，位图的粒度无法适应这种变化。链表虽然遍历是 O(n)，但每个块自带大小信息，天然支持变长分配。</p><p><strong>为什么 BlockHeader 放在块的前面而不是后面？</strong> 有些分配器把元数据放在 payload 之后。但前面放置有一个显著优势——free 时只需要做 <code>ptr - HEADER_SIZE</code> 就能定位 header，不需要知道块的总大小。如果 header 放在后面，你就需要知道 payload 的大小才能算出 header 的位置，形成了一个&quot;先有鸡还是先有蛋&quot;的问题。</p><p><strong>alloc 返回的内存为什么总是清零的？</strong> C 标准对 <code>malloc</code> 没有这个要求——malloc 返回的内存内容是未定义的。但 Cinux 的 alloc 总是清零 payload。这有两个好处：安全（不会泄露上一个使用者的数据）和方便（调用者不需要手动 memset）。代价是每次 alloc 多了一次 memzero 调用，但 memzero 的开销在内核堆的规模下可以忽略。Linux 的 <code>kzalloc</code> 也是同样的&quot;清零分配&quot;语义。</p><p><strong>内核堆和用户态堆有什么不同？</strong> 用户态的 <code>malloc</code> 由 C 标准库（glibc、musl 等）实现，底层调用 <code>brk</code> 或 <code>mmap</code> 系统调用从操作系统获取内存。内核堆没有&quot;更底层&quot;可以求助——它必须自己管理物理页的分配和虚拟地址的映射。这意味着内核堆的实现必须直接调用 PMM 和 VMM，而不是像用户态那样通过系统调用。这种&quot;自举&quot;的性质使得内核堆的实现比用户态 malloc 更底层，但也更直接——你看到的每一行代码都在真实地操作硬件资源。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>本章搭建了堆分配器的骨架——BlockHeader 数据结构和 Heap 类的接口定义，以及 init 和 dump_stats 的完整实现。下一章我们将实现 alloc 的 first-fit 搜索和块分裂逻辑，让堆真正能分配内存。</p><table tabindex="0"><thead><tr><th>概念</th><th>要点</th></tr></thead><tbody><tr><td>BlockHeader</td><td>32 字节 packed 结构体：magic(0xDEADBEEF) + size + free + _pad[12] + next</td></tr><tr><td>static_assert</td><td>编译期保证 sizeof(BlockHeader) == 32，任何字段修改导致大小变化都会被立即捕获</td></tr><tr><td>[[gnu::packed]]</td><td>消除编译器自动插入的对齐填充，确保精确控制内存布局</td></tr><tr><td>Heap::init</td><td>对齐大小 -&gt; 逐页映射 -&gt; 清零 -&gt; 创建初始空闲块 -&gt; 保存元数据</td></tr><tr><td>空闲链表</td><td>free_list_ 指向链表头，空闲块通过 next 串联</td></tr><tr><td>堆地址</td><td>0xFFFF800000000000，64 KB 初始大小，在 VMM 之后初始化</td></tr><tr><td>dump_stats</td><td>遍历空闲链表统计 free_total 和 block_count，配合 used_ 输出四项指标</td></tr><tr><td>地址空间安全性</td><td>堆地址远离内核代码段、页表和 MMIO 区域，避免重叠</td></tr><tr><td>初始化顺序</td><td>对齐大小 -&gt; 逐页映射 -&gt; 清零 -&gt; 创建初始空闲块 -&gt; 保存元数据，五步顺序不可调换</td></tr></tbody></table>`,92)])])}const m=a(s,[["render",c]]);export{u as __pageData,m as default};
